package com.chrisb97.warehouse.controller;
import com.chrisb97.warehouse.config.AppContext;import com.chrisb97.warehouse.model.Location;import com.chrisb97.warehouse.model.Product;import com.chrisb97.warehouse.util.AlertUtil;import javafx.beans.property.SimpleStringProperty;import javafx.collections.FXCollections;import javafx.fxml.FXML;import javafx.scene.control.*;
public class LocationsController{@FXML private TextField searchField,codeField,aisleField,sideField,positionField,xField,yField,capacityField;@FXML private CheckBox activeCheck;@FXML private ListView<Product> productsAtLocation;@FXML private TableView<Location> table;@FXML private TableColumn<Location,String> codeColumn,aisleColumn,sideColumn,positionColumn,coordinatesColumn,capacityColumn,statusColumn;private Location selected;
@FXML public void initialize(){codeColumn.setCellValueFactory(d->new SimpleStringProperty(d.getValue().getCode()));aisleColumn.setCellValueFactory(d->new SimpleStringProperty(d.getValue().getAisle()));sideColumn.setCellValueFactory(d->new SimpleStringProperty(String.valueOf(d.getValue().getSide())));positionColumn.setCellValueFactory(d->new SimpleStringProperty(String.valueOf(d.getValue().getPosition())));coordinatesColumn.setCellValueFactory(d->new SimpleStringProperty(d.getValue().getXCoordinate()+", "+d.getValue().getYCoordinate()));capacityColumn.setCellValueFactory(d->new SimpleStringProperty(String.valueOf(d.getValue().getMaxCapacity())));statusColumn.setCellValueFactory(d->new SimpleStringProperty(d.getValue().isActive()?"Active":"Inactive"));table.getSelectionModel().selectedItemProperty().addListener((o,a,b)->edit(b));searchField.textProperty().addListener((o,a,b)->refresh());clear();refresh();}
private void refresh(){table.setItems(FXCollections.observableArrayList(AppContext.getInstance().locations().search(searchField.getText())));}private void edit(Location l){selected=l;if(l==null)return;codeField.setText(l.getCode());aisleField.setText(l.getAisle());sideField.setText(String.valueOf(l.getSide()));positionField.setText(String.valueOf(l.getPosition()));xField.setText(String.valueOf(l.getXCoordinate()));yField.setText(String.valueOf(l.getYCoordinate()));capacityField.setText(String.valueOf(l.getMaxCapacity()));activeCheck.setSelected(l.isActive());productsAtLocation.setItems(FXCollections.observableArrayList(AppContext.getInstance().products().search(l.getCode(),null,false)));productsAtLocation.setCellFactory(v->new ListCell<>(){protected void updateItem(Product p,boolean empty){super.updateItem(p,empty);setText(empty||p==null?null:p.getSku()+" — "+p.getName()+" ("+p.getQuantity()+")");}});}
@FXML private void save(){try{Location l=selected==null?new Location():selected;l.setCode(codeField.getText());l.setAisle(aisleField.getText().trim().toUpperCase());l.setSide(Integer.parseInt(sideField.getText()));l.setPosition(Integer.parseInt(positionField.getText()));l.setXCoordinate(Integer.parseInt(xField.getText()));l.setYCoordinate(Integer.parseInt(yField.getText()));l.setMaxCapacity(Integer.parseInt(capacityField.getText()));l.setActive(activeCheck.isSelected());AppContext.getInstance().locations().save(l);AlertUtil.info("Saved","Location saved successfully.");clear();refresh();}catch(NumberFormatException e){AlertUtil.error("Invalid value","Side, position, coordinates and capacity must be integers.");}catch(RuntimeException e){AlertUtil.error("Could not save location",e.getMessage());}}
@FXML private void newLocation(){clear();table.getSelectionModel().clearSelection();}@FXML private void toggleStatus(){if(selected==null){AlertUtil.error("No selection","Select a location first.");return;}try{AppContext.getInstance().locations().setActive(selected.getId(),!selected.isActive());clear();refresh();}catch(RuntimeException e){AlertUtil.error("Could not change status",e.getMessage());}}
private void clear(){selected=null;codeField.clear();aisleField.setText("A");sideField.setText("1");positionField.setText("1");xField.setText("0");yField.setText("0");capacityField.setText("100");activeCheck.setSelected(true);if(productsAtLocation!=null)productsAtLocation.getItems().clear();}}
